<?php
if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_OAuth { const META_TOKEN = 'tct_todoist_access_token'; const META_CONNECTED_AT = 'tct_todoist_connected_at'; const META_STATE = 'tct_todoist_oauth_state'; const META_REDIRECT_TO = 'tct_todoist_oauth_redirect_to'; public function __construct() { add_action( 'admin_post_tct_start_oauth', array( $this, 'handle_start_oauth' ) ); add_action( 'admin_post_tct_oauth_callback', array( $this, 'handle_oauth_callback' ) ); add_action( 'admin_post_tct_disconnect', array( $this, 'handle_disconnect' ) ); } public static function get_token( $user_id ) { $token = get_user_meta( $user_id, self::META_TOKEN, true ); return is_string( $token ) ? $token : ''; } public static function is_connected( $user_id ) { $token = self::get_token( $user_id ); return ! empty( $token ); } public static function connect_url( $redirect_to = '' ) { if ( ! $redirect_to ) { $redirect_to = wp_get_referer(); } if ( ! $redirect_to ) { $redirect_to = home_url( '/' ); } return add_query_arg( array( 'action' => 'tct_start_oauth', 'redirect_to' => rawurlencode( $redirect_to ), ), admin_url( 'admin-post.php' ) ); } public static function disconnect_url( $redirect_to = '' ) { if ( ! $redirect_to ) { $redirect_to = wp_get_referer(); } if ( ! $redirect_to ) { $redirect_to = home_url( '/' ); } $url = add_query_arg( array( 'action' => 'tct_disconnect', 'redirect_to' => rawurlencode( $redirect_to ), ), admin_url( 'admin-post.php' ) ); return wp_nonce_url( $url, 'tct_disconnect' ); } public function handle_start_oauth() { if ( ! is_user_logged_in() ) { wp_safe_redirect( wp_login_url() ); exit; } $user_id = get_current_user_id(); $client_id = TCT_Admin::get_client_id(); $client_secret = TCT_Admin::get_client_secret(); if ( empty( $client_id ) || empty( $client_secret ) ) { $redirect_to = wp_get_referer(); if ( ! $redirect_to ) { $redirect_to = home_url( '/' ); } $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_error', 'missing_client_credentials' ); wp_safe_redirect( $redirect_to ); exit; } $redirect_to = isset( $_GET['redirect_to'] ) ? rawurldecode( sanitize_text_field( wp_unslash( $_GET['redirect_to'] ) ) ) : ''; if ( ! $redirect_to ) { $redirect_to = wp_get_referer(); } if ( ! $redirect_to ) { $redirect_to = home_url( '/' ); } update_user_meta( $user_id, self::META_REDIRECT_TO, esc_url_raw( $redirect_to ) ); $state = wp_generate_password( 32, false, false ); update_user_meta( $user_id, self::META_STATE, $state ); $authorize_url = add_query_arg( array( 'client_id' => $client_id, 'scope' => 'data:read_write', 'state' => $state, ), 'https://todoist.com/oauth/authorize' ); wp_redirect( esc_url_raw( $authorize_url ) ); exit; } public function handle_oauth_callback() { if ( ! is_user_logged_in() ) { wp_safe_redirect( wp_login_url() ); exit; } $user_id = get_current_user_id(); $redirect_to = get_user_meta( $user_id, self::META_REDIRECT_TO, true ); if ( ! $redirect_to ) { $redirect_to = home_url( '/' ); } $error = isset( $_GET['error'] ) ? sanitize_text_field( wp_unslash( $_GET['error'] ) ) : ''; if ( $error ) { delete_user_meta( $user_id, self::META_STATE ); $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_oauth', 'error_' . $error ); wp_safe_redirect( $redirect_to ); exit; } $code = isset( $_GET['code'] ) ? sanitize_text_field( wp_unslash( $_GET['code'] ) ) : ''; $state = isset( $_GET['state'] ) ? sanitize_text_field( wp_unslash( $_GET['state'] ) ) : ''; $expected_state = get_user_meta( $user_id, self::META_STATE, true ); if ( ! $expected_state || $state !== $expected_state ) { $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_oauth', 'invalid_state' ); wp_safe_redirect( $redirect_to ); exit; } if ( empty( $code ) ) { $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_oauth', 'missing_code' ); wp_safe_redirect( $redirect_to ); exit; } $client_id = TCT_Admin::get_client_id(); $client_secret = TCT_Admin::get_client_secret(); if ( empty( $client_id ) || empty( $client_secret ) ) { $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_oauth', 'missing_client_credentials' ); wp_safe_redirect( $redirect_to ); exit; } $token = $this->exchange_code_for_token( $client_id, $client_secret, $code ); if ( is_wp_error( $token ) ) { delete_user_meta( $user_id, self::META_STATE ); $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_oauth', 'token_exchange_failed' ); wp_safe_redirect( $redirect_to ); exit; } update_user_meta( $user_id, self::META_TOKEN, $token ); update_user_meta( $user_id, self::META_CONNECTED_AT, current_time( 'mysql', true ) ); delete_user_meta( $user_id, self::META_STATE ); TCT_Sync::sync_labels( $user_id ); $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_oauth', 'success' ); wp_safe_redirect( $redirect_to ); exit; } public function handle_disconnect() { if ( ! is_user_logged_in() ) { wp_safe_redirect( wp_login_url() ); exit; } check_admin_referer( 'tct_disconnect' ); $user_id = get_current_user_id(); $redirect_to = isset( $_GET['redirect_to'] ) ? rawurldecode( sanitize_text_field( wp_unslash( $_GET['redirect_to'] ) ) ) : ''; if ( ! $redirect_to ) { $redirect_to = wp_get_referer(); } if ( ! $redirect_to ) { $redirect_to = home_url( '/' ); } delete_user_meta( $user_id, self::META_TOKEN ); delete_user_meta( $user_id, self::META_CONNECTED_AT ); delete_user_meta( $user_id, self::META_STATE ); delete_user_meta( $user_id, self::META_REDIRECT_TO ); delete_user_meta( $user_id, TCT_Sync::META_LAST_SYNC_AT ); delete_user_meta( $user_id, TCT_Sync::META_LAST_SYNC_STATUS ); delete_user_meta( $user_id, TCT_Sync::META_LABELS_CACHE ); delete_user_meta( $user_id, TCT_Sync::META_LABELS_CACHE_AT ); TCT_Sync::delete_user_data( $user_id ); $redirect_to = TCT_Utils::add_query_arg_safe( $redirect_to, 'tct_disconnected', '1' ); wp_safe_redirect( $redirect_to ); exit; } private function exchange_code_for_token( $client_id, $client_secret, $code ) { $endpoint = 'https://todoist.com/oauth/access_token'; $body = array( 'client_id' => $client_id, 'client_secret' => $client_secret, 'code' => $code, 'redirect_uri' => TCT_Admin::get_oauth_redirect_uri(), ); $resp = wp_remote_post( $endpoint, array( 'timeout' => 30, 'body' => $body, ) ); if ( is_wp_error( $resp ) ) { return $resp; } $code_http = (int) wp_remote_retrieve_response_code( $resp ); $body_raw = wp_remote_retrieve_body( $resp ); if ( $code_http < 200 || $code_http >= 300 ) { return new WP_Error( 'tct_token_http_error', 'Token exchange HTTP error: ' . $code_http, array( 'body' => $body_raw ) ); } $json = json_decode( $body_raw, true ); if ( null === $json || empty( $json['access_token'] ) ) { return new WP_Error( 'tct_token_parse_error', 'Token exchange returned invalid response.', array( 'body' => $body_raw ) ); } return sanitize_text_field( $json['access_token'] ); } } 
